// ----- Lookup helpers ------------------------------------------------------

const SKIN_BY_ID = new Map<number, SkinMeta>(SKIN_METADATA.map((s) => [s.id, s]));

/** Get a human-friendly skin label by SkinId. Falls back to `Skin <id>`. */
export function getSkinDisplayName(skinId: number): string {
  return SKIN_BY_ID.get(skinId)?.displayName ?? `Skin ${skinId}`;
}

/** Look up the Prestige variant skin for a character by their internal name (e.g. "BellMage"). */
export function getPrestigeSkin(characterName: string): SkinMeta | undefined {
  return SKIN_METADATA.find((s) => s.characterName === characterName && s.variant === 'Prestige');
}

/** All skins available for a character (by internal name), excluding hidden variants. */
export function getSkinsForCharacter(characterName: string): SkinMeta[] {
  return SKIN_METADATA.filter((s) => s.characterName === characterName);
}
